To repro: Use 0, false, or "" as default values in example11.cpp

Fix: specify explicit CTOR for arg

diff --git a/include/pybind11/attr.h b/include/pybind11/attr.h
index 10d848a..907e6ed 100644
--- a/include/pybind11/attr.h
+++ b/include/pybind11/attr.h
@@ -18,14 +18,14 @@ template <typename T> struct arg_t;
 
 /// Annotation for keyword arguments
 struct arg {
-    constexpr arg(const char *name) : name(name) { }
+    constexpr explicit arg(const char *name) : name(name) { }
 
     template <typename T>
     constexpr arg_t<T> operator=(const T &value) const { return {name, value}; }
     template <typename T, size_t N>
     constexpr arg_t<const T *> operator=(T const (&value)[N]) const {
         return operator=((const T *) value);
-    };
+    }
 
     const char *name;
 };
@@ -40,7 +40,7 @@ template <typename T> struct arg_t : public arg {
 
 inline namespace literals {
 /// String literal version of arg
-constexpr arg operator"" _a(const char *name, size_t) { return {name}; }
+constexpr arg operator"" _a(const char *name, size_t) { return {arg(name)}; }
 }
 
 /// Annotation for methods

Nice work on this encoder.

Looking at the documentation for [quantisation](https://github.com/tilezen/mapbox-vector-tile#quantization), it states that:

> When encoding, pass in the bounds in the form (minx, maxx, miny, maxy) and the coordinates will be scaled appropriately during encoding.

The following example then has:

```python
mapbox_vector_tile.encode([
      {
        "name": "water",
        "features": [
          {
            "geometry":"POINT(15 15)",
            "properties":{
              "foo":"bar",
            }
          }
        ]
      }
    ], quantize_bounds=(10.0, 10.0, 20.0, 20.0))
```
Those bounds look like minx, miny, maxx, maxy, and indeed the source code:

```python
def quantize(self, shape, bounds):
        minx, miny, maxx, maxy = bounds
```

Easy fix that only affects that bit of documentation in the readme.

